const root = $json ?? {};
const body = root.body && typeof root.body === 'object' ? root.body : root;
const rawHeaders = root.headers ?? body.headers ?? {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);

const configuredSecret = $env.N8N_OPERATION_ASSISTANT_SECRET || '';
const expectedSecret = configuredSecret && !configuredSecret.toLowerCase().includes('substitua')
  ? configuredSecret
  : '';
const receivedSecret = headers['x-axon-webhook-secret'];

if (expectedSecret && receivedSecret !== expectedSecret) {
  return [{
    json: {
      ok: false,
      statusCode: 401,
      responseBody: { ok: false, error: 'invalid_secret' }
    }
  }];
}

const stageKey = body.stageKey
  || body.stage_key
  || body.stage?.stageKey
  || body.stage?.key
  || body.stage?.lessonId
  || body.lessonId
  || body.currentLesson;
const agentId = body.agent_id
  || body.agentId
  || body.stage?.agentId
  || body.agent?.id
  || 'auto';
const moduleId = body.module?.id || body.stage?.moduleId || body.moduleId || 'module-1';

const errors = [];
if (!body.member?.id) errors.push('member.id');
if (!body.project?.id) errors.push('project.id');
if (!body.message) errors.push('message');
if (!stageKey) errors.push('stageKey');

if (errors.length) {
  return [{
    json: {
      ok: false,
      statusCode: 400,
      responseBody: { ok: false, error: `missing_fields:${errors.join(',')}` }
    }
  }];
}

const payload = {
  ...body,
  stageKey,
  agent_id: agentId,
  module: body.module || { id: moduleId },
  stage: body.stage || { lessonId: stageKey, agentId }
};

return [{
  json: {
    ok: true,
    payload,
    agent_id: agentId,
    project_id: body.project.id,
    member_id: body.member.id,
    stage_key: stageKey
  }
}];

const row = $json;
const payload = row.payload_json;
const agentSequence = ['business_modeling', 'target_audience', 'strategic_differentiation', 'strategic_pricing', 'product_concept', 'visual_identity'];
const completedAgents = new Set((row.history_json || [])
  .filter((run) => run.status === 'completed' && run.transfer_block)
  .map((run) => run.agent_id));
const agentId = row.agent_id && row.agent_id !== 'auto'
  ? row.agent_id
  : agentSequence.find((id) => !completedAgents.has(id)) || 'visual_identity';

const promptByAgent = {
  business_modeling: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/01-modelagem-de-negocio.md',
  target_audience: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/02-publico-alvo.md',
  strategic_differentiation: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/03-diferencial-estrategico.md',
  strategic_pricing: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/04-precificacao-estrategica.md',
  product_concept: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/05-conceito-de-produto.md',
  visual_identity: 'USE O PROMPT DO ARQUIVO source-material/Agents/revised-module-1/06-identidade-visual.md'
};

const instructions = [
  promptByAgent[agentId] || promptByAgent.business_modeling,
  '',
  'Voce esta dentro da area de membros da Axon. Nao mencione ChatGPT personalizado, nao peca copia manual e nao mande o aluno abrir outro agente.',
  'Se ainda faltarem dados, responda como conversa natural e faca no maximo duas perguntas.',
  'Quando tiver dados suficientes, devolva JSON valido com agent_id, status, project_section, summary_for_user, transfer_block e next_recommended_agent.'
].join('\n');

const context = {
  agent_id: agentId,
  stage_key: row.stage_key,
  project: payload.project,
  module: payload.module,
  stage: payload.stage,
  recent_transfer_blocks: row.history_json,
  thread: payload.thread || []
};

return [{
  json: {
    payload,
    project_row_json: row.project_row_json,
    agent_id: agentId,
    stage_key: row.stage_key,
    openai_request: {
      model: $env.OPENAI_OPERATION_MODEL || 'gpt-5.1',
      instructions,
      input: [
        {
          role: 'user',
          content: [
            {
              type: 'input_text',
              text: JSON.stringify({ context, user_message: payload.message })
            }
          ]
        }
      ]
    }
  }
}];

const response = $json;
const text = response.output_text || response.output?.flatMap((item) => item.content || []).map((content) => content.text || '').join('\n') || '';
let parsed;
try {
  parsed = JSON.parse(text);
} catch {
  parsed = {
    agent_id: $('Build OpenAI Request').item.json.agent_id,
    status: 'needs_input',
    project_section: null,
    summary_for_user: text || 'Nao consegui interpretar a resposta do agente.',
    transfer_block: null,
    next_recommended_agent: null
  };
}

return [{
  json: {
    ...parsed,
    answer: parsed.summary_for_user || text,
    raw_response_json: response,
    openai_response_id: response.id || null,
    payload: $('Build OpenAI Request').item.json.payload,
    project_row_json: $('Build OpenAI Request').item.json.project_row_json,
    stage_key: $('Build OpenAI Request').item.json.stage_key
  }
}];

function q(value) {
  return `'${String(value ?? '').replace(/'/g, "''")}'`;
}
function qJson(value) {
  return `'${JSON.stringify(value ?? null).replace(/'/g, "''")}'::jsonb`;
}
const project = $json.project_row_json;
const payload = $json.payload;
const section = $json.project_section || $json.agent_id || 'conversa';
const transferBlock = $json.transfer_block || null;
const strategicPatch = transferBlock ? `jsonb_set(coalesce(strategic_plan_json, '{}'::jsonb), '{${section}}', ${qJson(transferBlock)}, true)` : 'strategic_plan_json';

const query = `
insert into operation_agent_runs (
  project_id,
  member_id,
  stage_key,
  agent_id,
  status,
  user_message,
  assistant_answer,
  project_section,
  transfer_block_json,
  raw_response_json,
  openai_response_id
) values (
  ${q(project.id)}::uuid,
  ${q(project.member_id)}::uuid,
  ${q($json.stage_key)},
  ${q($json.agent_id)},
  ${q($json.status || 'needs_input')},
  ${q(payload.message)},
  ${q($json.answer)},
  ${q($json.project_section)},
  ${qJson(transferBlock)},
  ${qJson($json.raw_response_json)},
  ${q($json.openai_response_id)}
);

insert into operation_conversation_messages (project_id, member_id, stage_key, role, content, metadata_json)
values
  (${q(project.id)}::uuid, ${q(project.member_id)}::uuid, ${q($json.stage_key)}, 'user', ${q(payload.message)}, ${qJson({ agent_id: $json.agent_id })}),
  (${q(project.id)}::uuid, ${q(project.member_id)}::uuid, ${q($json.stage_key)}, 'assistant', ${q($json.answer)}, ${qJson({ agent_id: $json.agent_id, status: $json.status })});

update operation_projects
set
  strategic_plan_json = ${strategicPatch},
  updated_at = now()
where id = ${q(project.id)}::uuid;

select true as saved;
`;

return [{ json: { ...$json, query } }];
